package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullHandlingWithNullStringNull() throws Exception {
        // Create a CSVFormat instance (DEFAULT)
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set the private final nullString field to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier on the field (for JDK 12+ this might not be needed or possible)
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, null);

        // isNullHandling() should return false because nullString is null
        assertFalse(format.isNullHandling());
    }

    @Test
    void testIsNullHandlingWithNullStringNonNull() throws Exception {
        // Create a CSVFormat instance (DEFAULT)
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set the private final nullString field to "NULL"
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier on the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, "NULL");

        // isNullHandling() should return true because nullString is non-null
        assertTrue(format.isNullHandling());
    }
}
